# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory collaboration platform that manages users,
projects, tasks, messaging, performance analytics and reporting.

The public surface is intentionally explicit: every entity returned from a
getter is a defensive deep copy so callers can never mutate internal state by
accident.  All mutating operations are serialized through a single shared
lock, which lets the manager be used safely from multiple threads.

The module is implemented with the Python standard library only and uses
ASCII characters exclusively so it remains portable across environments.
"""

import copy
import csv
import enum
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from typing import Dict, List, Optional, Set, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(enum.Enum):
    """Roles a user can hold within the platform."""

    MEMBER = "member"
    ADMIN = "admin"
    GUEST = "guest"


class TaskStatus(enum.Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(enum.Enum):
    """Supported export formats for generated reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(enum.Enum):
    """Kinds of reports the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class Attachment:
    """A file attached to a message."""

    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class User:
    """A platform user."""

    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    """A project that groups tasks and discussions."""

    id: int
    name: str
    description: str
    start_date: datetime
    end_date: datetime
    owner_id: int


@dataclass
class Task:
    """A unit of work that can be assigned and tracked."""

    id: int
    project_id: int
    title: str
    status: TaskStatus
    assignee_id: Optional[int]
    deadline: Optional[datetime]
    started_at: Optional[datetime]
    completed_at: Optional[datetime]
    created_at: datetime


@dataclass
class Message:
    """A message posted against a project or task."""

    id: int
    author_id: int
    body: str
    project_id: Optional[int]
    task_id: Optional[int]
    parent_id: Optional[int]
    attachments: List[Attachment]
    created_at: datetime
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    """A peer rating submitted for a user."""

    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str
    task_id: Optional[int]
    created_at: datetime


# ---------------------------------------------------------------------------
# Internal store
# ---------------------------------------------------------------------------
class _Store:
    """A thin namespaced container that shares the manager's lock.

    Each logical area of the manager (users, projects, ...) is exposed as a
    ``_Store`` so that callers and tests can observe that a single lock guards
    the whole system.  The ``by_id`` mapping holds the primary records for the
    area.
    """

    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock
        self.by_id: Dict[int, object] = {}


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """In-memory, thread-safe team collaboration manager."""

    def __init__(self, now=None) -> None:
        # A single reentrant lock guards every piece of mutable state.
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._id_counter = 0

        # Namespaced stores -- all share the same lock instance.
        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)  # ratings live here
        self.reports = _Store(self._lock)

        # Secondary indices for efficient lookups.
        self._tasks_by_project: Dict[int, Set[int]] = {}
        self._tasks_by_assignee: Dict[int, Set[int]] = {}
        self._messages_by_project: Dict[int, Set[int]] = {}
        self._messages_by_task: Dict[int, Set[int]] = {}
        self._ratings_by_ratee: Dict[int, List[int]] = {}

    # ------------------------------------------------------------------
    # Low level helpers
    # ------------------------------------------------------------------
    def _next_id(self) -> int:
        """Allocate the next globally-unique identifier.

        Must be called while holding ``self._lock``.
        """

        self._id_counter += 1
        return self._id_counter

    def _get_user_raw(self, user_id: int) -> User:
        user = self.users.by_id.get(user_id)
        if user is None:
            raise NotFoundError("User {0} not found".format(user_id))
        return user

    def _get_project_raw(self, project_id: int) -> Project:
        project = self.projects.by_id.get(project_id)
        if project is None:
            raise NotFoundError("Project {0} not found".format(project_id))
        return project

    def _get_task_raw(self, task_id: int) -> Task:
        task = self.tasks.by_id.get(task_id)
        if task is None:
            raise NotFoundError("Task {0} not found".format(task_id))
        return task

    def _get_message_raw(self, message_id: int) -> Message:
        message = self.messages.by_id.get(message_id)
        if message is None:
            raise NotFoundError("Message {0} not found".format(message_id))
        return message

    @staticmethod
    def _require_non_empty(value, label: str) -> str:
        if not isinstance(value, str) or not value.strip():
            raise ValidationError("{0} must be a non-empty string".format(label))
        return value

    @staticmethod
    def _validate_email(email: str) -> str:
        if not isinstance(email, str) or not email.strip() or "@" not in email:
            raise ValidationError("Invalid email address")
        return email

    def _tasks_for_user(self, user_id: int) -> List[Task]:
        ids = self._tasks_by_assignee.get(user_id, set())
        return [self.tasks.by_id[tid] for tid in ids if tid in self.tasks.by_id]

    def _tasks_for_project(self, project_id: int) -> List[Task]:
        ids = self._tasks_by_project.get(project_id, set())
        return [self.tasks.by_id[tid] for tid in ids if tid in self.tasks.by_id]

    @staticmethod
    def _average_completion_time(tasks: List[Task]) -> Optional[float]:
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.started_at is not None
            and t.completed_at is not None
        ]
        if not durations:
            return None
        return sum(durations) / len(durations)

    @staticmethod
    def _completion_rate(tasks: List[Task]) -> float:
        if not tasks:
            return 0.0
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        return completed / len(tasks)

    def _ratings_for_user(self, user_id: int) -> List[Rating]:
        ids = self._ratings_by_ratee.get(user_id, [])
        return [self.performance.by_id[rid] for rid in ids if rid in self.performance.by_id]

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER) -> User:
        with self._lock:
            self._require_non_empty(username, "username")
            self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            for existing in self.users.by_id.values():
                if existing.username == username:
                    raise DuplicateError("username already exists")
                if existing.email == email:
                    raise DuplicateError("email already exists")

            user_id = self._next_id()
            user = User(
                id=user_id,
                username=username,
                email=email,
                role=role,
                created_at=self._now(),
            )
            self.users.by_id[user_id] = user
            return copy.deepcopy(user)

    def get_user(self, user_id) -> User:
        with self._lock:
            return copy.deepcopy(self._get_user_raw(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            users = sorted(self.users.by_id.values(), key=lambda u: u.id)
            return [copy.deepcopy(u) for u in users]

    def update_user(self, user_id, username=None, email=None, role=None) -> User:
        with self._lock:
            user = self._get_user_raw(user_id)

            if username is not None:
                self._require_non_empty(username, "username")
                for existing in self.users.by_id.values():
                    if existing.id != user_id and existing.username == username:
                        raise DuplicateError("username already exists")

            if email is not None:
                self._validate_email(email)
                for existing in self.users.by_id.values():
                    if existing.id != user_id and existing.email == email:
                        raise DuplicateError("email already exists")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if username is not None:
                user.username = username
            if email is not None:
                user.email = email
            if role is not None:
                user.role = role

            return copy.deepcopy(user)

    def delete_user(self, user_id) -> None:
        with self._lock:
            self._get_user_raw(user_id)

            for project in self.projects.by_id.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")

            for task in self._tasks_for_user(user_id):
                if task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks")

            del self.users.by_id[user_id]
            self._tasks_by_assignee.pop(user_id, None)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(
        self, name, start_date, end_date, owner_id, description=""
    ) -> Project:
        with self._lock:
            self._require_non_empty(name, "name")
            self._get_user_raw(owner_id)
            if end_date < start_date:
                raise ValidationError("end_date cannot precede start_date")

            project_id = self._next_id()
            project = Project(
                id=project_id,
                name=name,
                description=description,
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
            )
            self.projects.by_id[project_id] = project
            return copy.deepcopy(project)

    def get_project(self, project_id) -> Project:
        with self._lock:
            return copy.deepcopy(self._get_project_raw(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            projects = sorted(self.projects.by_id.values(), key=lambda p: p.id)
            return [copy.deepcopy(p) for p in projects]

    def update_project(
        self, project_id, name=None, description=None, start_date=None, end_date=None
    ) -> Project:
        with self._lock:
            project = self._get_project_raw(project_id)

            new_name = project.name if name is None else name
            new_description = (
                project.description if description is None else description
            )
            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date

            if name is not None:
                self._require_non_empty(name, "name")
            if new_end < new_start:
                raise ValidationError("end_date cannot precede start_date")

            project.name = new_name
            project.description = new_description
            project.start_date = new_start
            project.end_date = new_end
            return copy.deepcopy(project)

    def delete_project(self, project_id) -> None:
        with self._lock:
            self._get_project_raw(project_id)

            for task_id in list(self._tasks_by_project.get(project_id, set())):
                self._remove_task(task_id)
            self._tasks_by_project.pop(project_id, None)

            for message_id in list(self._messages_by_project.get(project_id, set())):
                self._remove_message(message_id)
            self._messages_by_project.pop(project_id, None)

            del self.projects.by_id[project_id]

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None) -> Task:
        with self._lock:
            project = self._get_project_raw(project_id)
            self._require_non_empty(title, "title")
            if assignee_id is not None:
                self._get_user_raw(assignee_id)
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")

            task_id = self._next_id()
            task = Task(
                id=task_id,
                project_id=project_id,
                title=title,
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                started_at=None,
                completed_at=None,
                created_at=self._now(),
            )
            self.tasks.by_id[task_id] = task
            self._tasks_by_project.setdefault(project_id, set()).add(task_id)
            if assignee_id is not None:
                self._tasks_by_assignee.setdefault(assignee_id, set()).add(task_id)
            return copy.deepcopy(task)

    def get_task(self, task_id) -> Task:
        with self._lock:
            return copy.deepcopy(self._get_task_raw(task_id))

    def list_tasks_by_project(self, project_id) -> List[Task]:
        with self._lock:
            if project_id not in self.projects.by_id:
                raise NotFoundError("Project {0} not found".format(project_id))
            tasks = sorted(self._tasks_for_project(project_id), key=lambda t: t.id)
            return [copy.deepcopy(t) for t in tasks]

    def list_tasks_by_assignee(self, user_id) -> List[Task]:
        with self._lock:
            if user_id not in self.users.by_id:
                raise NotFoundError("User {0} not found".format(user_id))
            tasks = sorted(self._tasks_for_user(user_id), key=lambda t: t.id)
            return [copy.deepcopy(t) for t in tasks]

    def assign_task(self, task_id, assignee_id) -> Task:
        with self._lock:
            task = self._get_task_raw(task_id)
            self._get_user_raw(assignee_id)
            self._set_assignee(task, assignee_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id, new_assignee_id) -> Task:
        with self._lock:
            task = self._get_task_raw(task_id)
            self._get_user_raw(new_assignee_id)
            self._set_assignee(task, new_assignee_id)
            return copy.deepcopy(task)

    def unassign_task(self, task_id) -> Task:
        with self._lock:
            task = self._get_task_raw(task_id)
            self._set_assignee(task, None)
            return copy.deepcopy(task)

    def _set_assignee(self, task: Task, assignee_id: Optional[int]) -> None:
        if task.assignee_id is not None:
            current = self._tasks_by_assignee.get(task.assignee_id)
            if current is not None:
                current.discard(task.id)
        task.assignee_id = assignee_id
        if assignee_id is not None:
            self._tasks_by_assignee.setdefault(assignee_id, set()).add(task.id)

    def set_deadline(self, task_id, deadline) -> Task:
        with self._lock:
            task = self._get_task_raw(task_id)
            if deadline is not None:
                project = self.projects.by_id.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id, status) -> Task:
        with self._lock:
            task = self._get_task_raw(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            return copy.deepcopy(task)

    def _remove_task(self, task_id: int) -> None:
        task = self.tasks.by_id.pop(task_id, None)
        if task is None:
            return
        project_tasks = self._tasks_by_project.get(task.project_id)
        if project_tasks is not None:
            project_tasks.discard(task_id)
        if task.assignee_id is not None:
            assignee_tasks = self._tasks_by_assignee.get(task.assignee_id)
            if assignee_tasks is not None:
                assignee_tasks.discard(task_id)
        for message_id in list(self._messages_by_task.get(task_id, set())):
            self._remove_message(message_id)
        self._messages_by_task.pop(task_id, None)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        parent_id=None,
        attachments=None,
    ) -> Message:
        with self._lock:
            self._get_user_raw(author_id)

            if project_id is None and task_id is None:
                raise ValidationError("a project_id or task_id is required")
            if project_id is not None and task_id is not None:
                raise ValidationError("provide only one of project_id or task_id")

            if project_id is not None:
                self._get_project_raw(project_id)
            if task_id is not None:
                self._get_task_raw(task_id)
            if parent_id is not None and parent_id not in self.messages.by_id:
                raise NotFoundError("Parent message {0} not found".format(parent_id))

            attachment_specs = list(attachments) if attachments else []
            has_body = isinstance(body, str) and body.strip() != ""
            if not has_body and not attachment_specs:
                raise ValidationError("message requires a body or an attachment")

            now = self._now()
            built_attachments = [
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
                for filename, data in attachment_specs
            ]

            message_id = self._next_id()
            message = Message(
                id=message_id,
                author_id=author_id,
                body=body,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built_attachments,
                created_at=now,
                edited_at=None,
            )
            self.messages.by_id[message_id] = message
            if project_id is not None:
                self._messages_by_project.setdefault(project_id, set()).add(message_id)
            if task_id is not None:
                self._messages_by_task.setdefault(task_id, set()).add(message_id)
            return copy.deepcopy(message)

    def edit_message(self, message_id, editor_id, new_body) -> Message:
        with self._lock:
            message = self._get_message_raw(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit a message")
            self._require_non_empty(new_body, "body")
            message.body = new_body
            message.edited_at = self._now()
            return copy.deepcopy(message)

    def add_attachment(self, message_id, user_id, filename, data) -> Message:
        with self._lock:
            message = self._get_message_raw(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may add attachments")
            self._require_non_empty(filename, "filename")
            attachment = Attachment(
                filename=filename,
                size=len(data),
                uploaded_by=user_id,
                uploaded_at=self._now(),
            )
            message.attachments.append(attachment)
            return copy.deepcopy(message)

    def list_messages_by_project(self, project_id) -> List[Message]:
        with self._lock:
            if project_id not in self.projects.by_id:
                raise NotFoundError("Project {0} not found".format(project_id))
            ids = self._messages_by_project.get(project_id, set())
            messages = sorted(
                (self.messages.by_id[mid] for mid in ids), key=lambda m: m.id
            )
            return [copy.deepcopy(m) for m in messages]

    def list_messages_by_task(self, task_id) -> List[Message]:
        with self._lock:
            if task_id not in self.tasks.by_id:
                raise NotFoundError("Task {0} not found".format(task_id))
            ids = self._messages_by_task.get(task_id, set())
            messages = sorted(
                (self.messages.by_id[mid] for mid in ids), key=lambda m: m.id
            )
            return [copy.deepcopy(m) for m in messages]

    def delete_message(self, message_id, user_id) -> None:
        with self._lock:
            message = self._get_message_raw(message_id)
            if message.author_id != user_id:
                raise AuthorizationError("only the author may delete a message")
            self._remove_message(message_id)

    def _remove_message(self, message_id: int) -> None:
        message = self.messages.by_id.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            bucket = self._messages_by_project.get(message.project_id)
            if bucket is not None:
                bucket.discard(message_id)
        if message.task_id is not None:
            bucket = self._messages_by_task.get(message.task_id)
            if bucket is not None:
                bucket.discard(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def get_completion_rate(self, user_id) -> float:
        with self._lock:
            self._get_user_raw(user_id)
            return self._completion_rate(self._tasks_for_user(user_id))

    def get_average_completion_time(self, user_id) -> Optional[float]:
        with self._lock:
            self._get_user_raw(user_id)
            return self._average_completion_time(self._tasks_for_user(user_id))

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None) -> Rating:
        with self._lock:
            if rater_id == ratee_id:
                raise ConflictError("a user cannot rate themselves")
            self._get_user_raw(rater_id)
            self._get_user_raw(ratee_id)
            if isinstance(score, bool) or not isinstance(score, int):
                raise ValidationError("score must be an integer between 1 and 5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None:
                self._get_task_raw(task_id)

            rating_id = self._next_id()
            rating = Rating(
                id=rating_id,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance.by_id[rating_id] = rating
            self._ratings_by_ratee.setdefault(ratee_id, []).append(rating_id)
            return copy.deepcopy(rating)

    def get_ratings_summary(self, user_id) -> dict:
        with self._lock:
            self._get_user_raw(user_id)
            ratings = self._ratings_for_user(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id) -> dict:
        with self._lock:
            self._get_user_raw(user_id)
            tasks = self._tasks_for_user(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
            not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)

            ratings = self._ratings_for_user(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id) -> dict:
        with self._lock:
            self._get_project_raw(project_id)
            tasks = self._tasks_for_project(project_id)
            total = len(tasks)

            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1

            now = self._now()
            overdue = sum(
                1
                for task in tasks
                if task.deadline is not None
                and task.status != TaskStatus.COMPLETED
                and task.deadline < now
            )

            per_assignee: Dict[int, dict] = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                entry = per_assignee.setdefault(
                    task.assignee_id, {"total": 0, "completed": 0}
                )
                entry["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    entry["completed"] += 1

            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": self._completion_rate(tasks),
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None) -> dict:
        with self._lock:
            if project_id is not None:
                self._get_project_raw(project_id)
                task_pool = self._tasks_for_project(project_id)
            else:
                task_pool = list(self.tasks.by_id.values())

            user_ids = sorted(
                {t.assignee_id for t in task_pool if t.assignee_id is not None}
            )

            rows = []
            for uid in user_ids:
                user_tasks = [t for t in task_pool if t.assignee_id == uid]
                total = len(user_tasks)
                completed = sum(
                    1 for t in user_tasks if t.status == TaskStatus.COMPLETED
                )
                rows.append(
                    {
                        "user_id": uid,
                        "total_tasks": total,
                        "completed_tasks": completed,
                        "completion_rate": self._completion_rate(user_tasks),
                        "average_completion_time": self._average_completion_time(
                            user_tasks
                        ),
                    }
                )

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id) -> dict:
        with self._lock:
            self._get_user_raw(user_id)
            tasks = sorted(self._tasks_for_user(user_id), key=lambda t: t.id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            ratings = self._ratings_for_user(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count if rating_count else 0.0
            )

            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": self._completion_rate(tasks),
                "average_completion_time": self._average_completion_time(tasks),
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": [copy.deepcopy(t) for t in tasks],
            }

    def export_report(self, report, report_format):
        if not isinstance(report, dict):
            raise ValidationError("report must be a mapping produced by this manager")
        if not isinstance(report_format, ReportFormat):
            raise ValidationError("report_format must be a ReportFormat")

        if report_format == ReportFormat.CSV:
            return self._report_to_csv(report)
        return self._report_to_pdf(report)

    # ------------------------------------------------------------------
    # Export helpers
    # ------------------------------------------------------------------
    @staticmethod
    def _csv_cell(value) -> str:
        if isinstance(value, bool):
            return str(value)
        if value is None:
            return ""
        if isinstance(value, (dict, list, tuple)):
            return str(value)
        return str(value)

    def _report_to_csv(self, report: dict) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)

        rows = report.get("rows")
        if isinstance(rows, list):
            header: List[str] = []
            for row in rows:
                if isinstance(row, dict):
                    for key in row.keys():
                        if key not in header:
                            header.append(key)
            if not header:
                header = ["user_id"]
            writer.writerow(header)
            for row in rows:
                if isinstance(row, dict):
                    writer.writerow([self._csv_cell(row.get(key)) for key in header])
        else:
            writer.writerow(["metric", "value"])
            for key, value in report.items():
                writer.writerow([key, self._csv_cell(value)])

        return buffer.getvalue()

    def _report_to_pdf(self, report: dict) -> bytes:
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        for key, value in report.items():
            if key == "report_type":
                continue
            if isinstance(value, (dict, list, tuple)):
                lines.append("{0}: {1} entries".format(key, len(value)))
            else:
                lines.append("{0}: {1}".format(key, value))
        return self._build_pdf(lines)

    @staticmethod
    def _build_pdf(lines: List[str]) -> bytes:
        def escape(text: str) -> str:
            return (
                text.replace("\\", "\\\\")
                .replace("(", "\\(")
                .replace(")", "\\)")
            )

        content_parts = ["BT", "/F1 12 Tf", "50 750 Td", "14 TL"]
        for index, line in enumerate(lines):
            escaped = escape(str(line))
            if index == 0:
                content_parts.append("({0}) Tj".format(escaped))
            else:
                content_parts.append("T*")
                content_parts.append("({0}) Tj".format(escaped))
        content_parts.append("ET")
        stream = "\n".join(content_parts).encode("latin-1", "replace")

        objects = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
            ),
            b"<< /Length "
            + str(len(stream)).encode("ascii")
            + b" >>\nstream\n"
            + stream
            + b"\nendstream",
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        out = bytearray(b"%PDF-1.4\n")
        offsets = []
        for number, body in enumerate(objects, start=1):
            offsets.append(len(out))
            out += "{0} 0 obj\n".format(number).encode("ascii")
            out += body
            out += b"\nendobj\n"

        xref_position = len(out)
        size = len(objects) + 1
        out += "xref\n0 {0}\n".format(size).encode("ascii")
        out += b"0000000000 65535 f \n"
        for offset in offsets:
            out += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        out += b"trailer\n"
        out += "<< /Size {0} /Root 1 0 R >>\n".format(size).encode("ascii")
        out += b"startxref\n"
        out += "{0}\n".format(xref_position).encode("ascii")
        out += b"%%EOF"
        return bytes(out)
